import java.io.IOException;
import java.util.Scanner;

public class CommandInjectionExample {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a directory name to list its contents: ");
        String directoryName = scanner.nextLine();

        try {
            // Vulnerable code that directly uses user input in the command
            Process process = Runtime.getRuntime().exec("ls " + directoryName);

            // Read and print the output of the command
            java.util.Scanner outputScanner = new java.util.Scanner(process.getInputStream());
            while (outputScanner.hasNextLine()) {
                System.out.println(outputScanner.nextLine());
            }
        } catch (IOException e) {
            e.printStackTrace();
        }

        scanner.close();
    }
}

